SCHEMA = {
    "name": "hp_efficiency_evaluator",
    "description": "Evaluates a proposed turn plan to enforce strict HP conservation. Use this to verify your plan before ending the turn.",
    "input_schema": {
        "type": "object",
        "properties": {
            "incoming_damage": {"type": "integer"},
            "planned_block": {"type": "integer"},
            "current_hp": {"type": "integer"}
        },
        "required": ["incoming_damage", "planned_block", "current_hp"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(incoming_damage, planned_block, current_hp):
    net_damage = max(0, incoming_damage - planned_block)
    is_fully_blocked = (net_damage == 0)
    survives = current_hp > net_damage

    recommendation = ""
    if not survives:
        recommendation = "FATAL: This plan results in death. You must increase planned_block."
    elif not is_fully_blocked:
        recommendation = "WARNING: Taking " + str(net_damage) + " damage. If you have unplayed block cards and energy, you MUST play them unless you have lethal."
    else:
        recommendation = "SAFE: Incoming damage is fully blocked."

    return {
        "net_damage_taken": net_damage,
        "is_fully_blocked": is_fully_blocked,
        "survives": survives,
        "recommendation": recommendation
    }

