    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(enemy_hp, poison_stacks):
    results = []
    for i in range(len(enemy_hp)):
        hp = enemy_hp[i]
        p = poison_stacks[i] if i < len(poison_stacks) else 0
        p = p if p is not None else 0

        if hp <= 0:
            results.append({"lethal_next_tick": False, "turns_to_lethal": 0, "total_poison_potential": 0})
            continue

        lethal_next = p >= hp
        max_dmg = (p * (p + 1)) // 2

        if hp > max_dmg:
            turns = None
        else:
            rem_hp = hp
            rem_p = p
            turns = 0
            while rem_hp > 0 and rem_p > 0:
                rem_hp -= rem_p
                rem_p -= 1
                turns += 1

        results.append({
            "hp": hp,
            "poison": p,
            "lethal_next_tick": lethal_next,
            "turns_to_lethal": turns,
            "total_poison_potential": max_dmg
        })
    return {"enemy_poison_analysis": results}

